var funProcess = require('child_process');
// 队列函数
function Callback(arr_model, fun_end){
  this.model = arr_model;
  this.end = fun_end;
};
Callback.prototype = {
  fire: function(){
    var _this = this;
    if(!this.model.length){
      this.end && this.end();
      return;
    }
    this.nowModel = this.model.shift();
    var item = this.nowModel;
    if(item['wait']){
      item['wait'](function(){
        var commend = typeof item['commend'] == 'string' ? item['commend'] : item['commend']();
        item['pre'] && item['pre']();
        funProcess.exec(commend, item['callback'].bind(_this));
      });
    }else{
      var commend = typeof item['commend'] == 'string' ? item['commend'] : item['commend']();
      item['pre'] && item['pre']();
      funProcess.exec(commend, item['callback'].bind(_this));
    }
  }
}
module.exports = Callback;